from django.contrib.auth.mixins import LoginRequiredMixin
from rest_framework.views import APIView
from rest_framework.permissions import IsAuthenticated
from django.utils.text import get_valid_filename
import os

class FileUploadView(APIView):
    permission_classes = [IsAuthenticated]
    ALLOWED_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.pdf', '.docx'}
    MAX_SIZE = 10 * 1024 * 1024  # 10MB

    def post(self, request):
        uploaded_file = request.FILES.get('file')
        if not uploaded_file:
            return Response({'error': 'No file'}, status=400)
        if uploaded_file.size > self.MAX_SIZE:
            return Response({'error': 'File too large'}, status=400)
        ext = os.path.splitext(uploaded_file.name)[1].lower()
        if ext not in self.ALLOWED_EXTENSIONS:
            return Response({'error': 'File type not allowed'}, status=400)
        safe_name = get_valid_filename(uploaded_file.name)
        upload_dir = f'uploads/{request.user.id}/'
        os.makedirs(upload_dir, exist_ok=True)
        path = os.path.join(upload_dir, safe_name)
        with open(path, 'wb') as f:
            f.write(uploaded_file.read())
        return Response({'path': path}, status=201)

